import type { SeasonPlan } from "../utils/plan-types";
import { ref, watch } from "vue";
import { useDecryption, useEncryption } from "../composables/use-crypto";

const STORAGE_KEY = "gameday-plan-id";
const FRAGMENT_PREFIX = "key=";

export const usePlanStore = defineStore("plan", () => {
  const plan = ref<SeasonPlan | null>(null);
  const key = ref<string | null>(null);
  const currentStep = ref(1);
  const onboardingPath = ref<"manual" | "auto" | null>(null);
  const isLoading = ref(false);
  const error = ref<string | null>(null);
  const eventSource = ref<EventSource | null>(null);

  // Local storage for the last active plan ID
  const lastPlanId = useLocalStorage(STORAGE_KEY, "");

  const { encryptData } = useEncryption();
  const { decryptBlob } = useDecryption();

  /**
   * Sync key with URL fragment
   */
  watch(key, (newKey) => {
    if (import.meta.server)
      return;

    if (newKey) {
      window.location.hash = `${FRAGMENT_PREFIX}${newKey}`;
    }
    else {
      window.location.hash = "";
    }
  });

  /**
   * Migrate the plan schema if needed.
   * This is a stub for future schema migrations.
   */
  function migrateIfNeeded(loadedPlan: SeasonPlan): SeasonPlan {
    const CURRENT_SCHEMA_VERSION = 1;

    if (loadedPlan.schemaVersion < CURRENT_SCHEMA_VERSION) {
      console.log(`Migrating plan from version ${loadedPlan.schemaVersion} to ${CURRENT_SCHEMA_VERSION}`);
      // TODO: Implement migration logic here
      // For now, just update the version
      loadedPlan.schemaVersion = CURRENT_SCHEMA_VERSION;
    }

    return loadedPlan;
  }

  async function loadPlan(id: string, decryptionKey: string) {
    isLoading.value = true;
    error.value = null;
    key.value = decryptionKey;

    try {
      const response = await $fetch<{ blob: string }>(`/api/${id}`);

      if (!response.blob) {
        throw new Error("No plan data found");
      }

      const decryptedData = await decryptBlob(response.blob, decryptionKey);
      let loadedPlan = JSON.parse(decryptedData) as SeasonPlan;

      // Run migration logic
      loadedPlan = migrateIfNeeded(loadedPlan);

      plan.value = loadedPlan;
      lastPlanId.value = id;
    }
    catch (err: any) {
      error.value = err.message || "Failed to load plan";
      console.error("Error loading plan:", err);
    }
    finally {
      isLoading.value = false;
    }
  }

  /**
   * Subscribe to real-time updates for the current plan via SSE.
   */
  function watchPlan() {
    if (import.meta.server || !plan.value?.id || !key.value)
      return;

    if (eventSource.value) {
      eventSource.value.close();
    }

    const id = plan.value.id;
    const decryptionKey = key.value;

    eventSource.value = new EventSource(`/api/${id}`);

    eventSource.value.onmessage = async (event) => {
      try {
        const encryptedBlob = event.data;
        if (!encryptedBlob)
          return;

        const decryptedData = await decryptBlob(encryptedBlob, decryptionKey);
        let updatedPlan = JSON.parse(decryptedData) as SeasonPlan;

        // Only update if the incoming revision is newer than our local one
        // This prevents overwriting unsaved local changes or re-applying our own save
        if (!plan.value || updatedPlan.rev > plan.value.rev) {
          console.log("Real-time update received: Rev", updatedPlan.rev);
          updatedPlan = migrateIfNeeded(updatedPlan);
          plan.value = updatedPlan;
        }
      }
      catch (err) {
        console.error("Failed to process real-time update:", err);
      }
    };

    eventSource.value.onerror = (err) => {
      console.error("SSE connection error:", err);
      // EventSource automatically retries by default
    };
  }

  function stopWatching() {
    if (eventSource.value) {
      eventSource.value.close();
      eventSource.value = null;
    }
  }

  async function savePlan() {
    if (!plan.value || !key.value) {
      error.value = "Missing plan or encryption key";
      return;
    }

    isLoading.value = true;
    error.value = null;

    try {
      // Increment revision and update timestamp
      plan.value.rev++;
      plan.value.lastUpdated = Date.now();

      const serializedPlan = JSON.stringify(plan.value);
      const encryptedBlob = await encryptData(serializedPlan, key.value);

      await $fetch(`/api/${plan.value.id}`, {
        method: "POST",
        body: {
          blob: encryptedBlob,
        },
      });

      lastPlanId.value = plan.value.id;
    }
    catch (err: any) {
      error.value = err.message || "Failed to save plan";
      console.error("Error saving plan:", err);
    }
    finally {
      isLoading.value = false;
    }
  }

  function createNewPlan(id: string, newKey: string) {
    key.value = newKey;
    plan.value = {
      id,
      club: {
        id: "1",
        name: "",
        contactEmail: "",
        homepage: "",
        lastUpdated: 0,
      },
      lastUpdated: Date.now(),
      skills: {},
      schemaVersion: 1,
      rev: 0,
      season: `${new Date().getFullYear()}/${new Date().getFullYear() + 1}`,
      members: {},
      teams: {},
      matches: {},
      gamedays: {},
      config: {
        locations: [],
        roles: [
          { id: "timekeeper", name: "Timekeeper", requiredSkillId: "", scope: "gameday" },
          { id: "scorekeeper", name: "Scorekeeper", requiredSkillId: "", scope: "match" },
          { id: "floor_manager", name: "Floor Manager", requiredSkillId: "", scope: "match" },
          { id: "media_liaison", name: "Media Liaison", requiredSkillId: "", scope: "match" },
        ],
      },
    };
    lastPlanId.value = id;
    currentStep.value = 1;
    onboardingPath.value = null;
  }

  function nextStep() {
    currentStep.value++;
  }

  function prevStep() {
    if (currentStep.value > 1) {
      currentStep.value--;
    }
  }

  function setPath(path: "manual" | "auto") {
    onboardingPath.value = path;
    nextStep();
  }

  /**
   * Extract key from URL fragment
   */
  function initFromUrl() {
    if (import.meta.server)
      return;

    const hash = window.location.hash.substring(1);
    if (hash.startsWith(FRAGMENT_PREFIX)) {
      key.value = hash.substring(FRAGMENT_PREFIX.length);
    }
  }

  return {
    plan,
    key,
    lastPlanId,
    currentStep,
    onboardingPath,
    isLoading,
    error,
    loadPlan,
    watchPlan,
    stopWatching,
    savePlan,
    createNewPlan,
    nextStep,
    prevStep,
    setPath,
    initFromUrl,
  };
});

/**
 * NuLiga API Client
 *
 * This client provides access to the NuLiga API for fetching club, roster, and match data.
 * Base implementation follows the routes provided in the API documentation.
 */

const NULIGA_BASE_URL = "https://hbde-app.liga.nu/rs/federation";
const DEFAULT_FEDERATION = "BHV";

export const nuligaApi = {
  /**
   * Get current season information.
   * (German: Info welche season)
   * @param federation The federation ID (default: BHV)
   */
  async getSeasonInfo(federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season`, {
      query: {
        currentSeason: true,
        includeTopRegions: true,
      },
    });
  },

  /**
   * Get general federation information.
   * (German: Verbandsinfo)
   * @param federation The federation ID (default: BHV)
   */
  async getFederationInfo(federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}`);
  },

  /**
   * Get championships for a specific season.
   * (German: Regionsinfos)
   * @param season The season string (e.g. "25/26")
   * @param federation The federation ID (default: BHV)
   */
  async getChampionships(season: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season/${encodeURIComponent(season)}/championship`, {
      query: {
        includeTopRegions: true,
      },
    });
  },

  /**
   * Get information for a specific championship.
   * (German: Regionsinfo 1 Region)
   * @param season The season string
   * @param championship The championship ID
   * @param federation The federation ID (default: BHV)
   */
  async getChampionship(season: string, championship: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season/${encodeURIComponent(season)}/championship/${encodeURIComponent(championship)}`);
  },

  /**
   * Get all groups (leagues) for a championship.
   * (German: Spielklassen)
   * @param season The season string
   * @param championship The championship ID
   * @param federation The federation ID (default: BHV)
   */
  async getAllGroups(season: string, championship: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season/${encodeURIComponent(season)}/championship/${encodeURIComponent(championship)}/allGroups`);
  },

  /**
   * Get a specific league group details.
   * (German: Spielklasse)
   * @param season The season string
   * @param championship The championship ID
   * @param league The league ID
   * @param group The group name
   * @param federation The federation ID (default: BHV)
   */
  async getGroupDetails(season: string, championship: string, league: string, group: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season/${encodeURIComponent(season)}/championship/${encodeURIComponent(championship)}/league/${encodeURIComponent(league)}/group/${encodeURIComponent(group)}`);
  },

  /**
   * Get current meetings for a specific group.
   * (German: Aktuelle Begegnungen)
   * @param season The season string
   * @param championship The championship ID
   * @param league The league ID
   * @param group The group name
   * @param federation The federation ID (default: BHV)
   */
  async getCurrentMeetings(season: string, championship: string, league: string, group: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season/${encodeURIComponent(season)}/championship/${encodeURIComponent(championship)}/league/${encodeURIComponent(league)}/group/${encodeURIComponent(group)}/meetings`, {
      query: {
        currentMeetings: true,
      },
    });
  },

  /**
   * Get tables for a specific group.
   * (German: Tabelle(n))
   * @param season The season string
   * @param championship The championship ID
   * @param league The league ID
   * @param group The group name
   * @param federation The federation ID (default: BHV)
   */
  async getTables(season: string, championship: string, league: string, group: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season/${encodeURIComponent(season)}/championship/${encodeURIComponent(championship)}/league/${encodeURIComponent(league)}/group/${encodeURIComponent(group)}/tables`);
  },

  /**
   * Get all meetings for a specific group.
   * (German: Alle Begegnungen)
   * @param season The season string
   * @param championship The championship ID
   * @param league The league ID
   * @param group The group name
   * @param federation The federation ID (default: BHV)
   */
  async getAllMeetings(season: string, championship: string, league: string, group: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/season/${encodeURIComponent(season)}/championship/${encodeURIComponent(championship)}/league/${encodeURIComponent(league)}/group/${encodeURIComponent(group)}/meetings`);
  },

  /**
   * Search for clubs in the NuLiga system.
   * (German: Club Suche)
   * @param query The search string (e.g. club name or zip code)
   * @param federation The federation ID (default: BHV)
   */
  async searchClubs(query: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/clubs`, {
      query: {
        searchString: query,
        firstResult: 0,
        maxResults: 50,
      },
    });
  },

  /**
   * Get general information about a specific club.
   * (German: Club Infos)
   * @param clubId The unique identifier of the club
   * @param federation The federation ID (default: BHV)
   */
  async getClubData(clubId: string, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/clubs/${clubId}`);
  },

  /**
   * Retrieve all meetings for a specific club.
   * (German: Alle Club Begegnungen)
   * @param clubId The unique identifier of the club
   * @param currentMeetings Whether to filter for current meetings only
   * @param federation The federation ID (default: BHV)
   */
  async getMatchDays(clubId: string, currentMeetings = false, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/clubs/${clubId}/meetings`, {
      query: {
        currentMeetings,
      },
    });
  },

  /**
   * Retrieve all rosters/teams registered for a club.
   * (German: Teams eines Clubs)
   * @param clubId The unique identifier of the club
   * @param currentSeason Whether to filter for the current season only
   * @param federation The federation ID (default: BHV)
   */
  async getRosters(clubId: string, currentSeason = true, federation = DEFAULT_FEDERATION) {
    return $fetch(`${NULIGA_BASE_URL}/${federation}/clubs/${clubId}/teams`, {
      query: {
        currentSeason,
      },
    });
  },
};

export type SeasonPlan = {
  id: string; // UUID
  schemaVersion: number; // 1
  rev: number; // Monotonic revision number for conflict detection
  lastUpdated: number; // timestamp (ms)

  club: Club;
  season: string; // e.g., "2025/2026"

  // Normalized Data
  members: Record<string, Member>;
  teams: Record<string, Team>;
  skills: Record<string, Skill>;
  gamedays: Record<string, Gameday>;
  matches: Record<string, Match>;

  config: Config;
};

type Club = {
  id: string;
  name: string;
  contactEmail: string;
  homepage: string;
  lastUpdated: number;
};

export type Config = {
  roles: Role[];
  locations: Location[];
};

export type Role = {
  id: string;
  name: string;
  icon?: string;
  scope: "gameday" | "match"; // Defines where this role can be assigned
  requiredSkillId?: string;
};

export type Location = {
  id: string;
  name: string;
  link?: string; // e.g., Google Maps link
};

export type Gameday = {
  id: string;
  date: string; // ISO 8601 (YYYY-MM-DD)
  locationId: string;
  matchIds: string[];
  slots: Slot[]; // Gameday-wide slots (e.g., Entrance, Catering)
  updatedAt: number;
};

export type Match = {
  id: string;
  time: string; // ISO 8601 or "HH:mm"
  homeTeam: string;
  awayTeam: string;
  helperTeamId?: string;
  slots: Slot[]; // Match-specific slots (e.g., Timekeeper, Secretary)
  updatedAt: number;
};

export type Slot = {
  id: string; // Unique ID for the slot itself
  roleId: string;
  assignedMemberId: string | null;
  updatedAt: number;
};

export type Member = {
  id: string;
  name: string;
  teamIds: string[];
  skillIds: string[];
  isManual: boolean;
  updatedAt: number;
};

export type Team = {
  id: string;
  name: string;
  isManual: boolean;
  updatedAt: number;
};

export type Skill = {
  id: string;
  name: string;
  updatedAt: number;
};

