      return;

    nuLigaTeams.forEach((team) => {
      plan.value!.teams[team.teamId] = {
        id: team.teamId,
        name: `${team.teamName} (${team.leagueName})`,
        isManual: false,
        updatedAt: Date.now(),
      };
    });
  }

  function importMatches(nuLigaMatches: NuLigaMatch[]) {
    if (!plan.value)
